export const quote = (customer: unknown, items: Item[]): number => {
  if (items.length === 0) return 5;
  const policyBase = items.reduce((sum, item) => sum + BASE_PREMIUMS[item.type], 0);
  const cursedSurcharge = items.reduce((sum, item) => sum + ((item as any).cursed ? BASE_PREMIUMS[item.type] / 2 : 0), 0);
  const firstInsurance = policyBase / 10;
  return policyBase + cursedSurcharge + firstInsurance + 5;
