import { describe, it, expect } from "vitest";
import { quote, claim } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  describe("quote", () => {
    it("should return 5G for empty item list (processing fee only)", () => {
      const customer = { yearsWithMHPCO: 0 };
      expect(quote(customer, [])).toBe(5);
    });
    it("should return correct premium for a single sword (new customer)", () => {
      const customer = { yearsWithMHPCO: 0 };
      const items = [{ type: "sword", material: "steel", enchantment: 0, cursed: false }];
      expect(quote(customer, items)).toBe(115);
    });
    it("should return correct premium for a single amulet (new customer)", () => {
      const customer = { yearsWithMHPCO: 0 };
      const items = [{ type: "amulet", material: "silver", enchantment: 0, cursed: false }];
      expect(quote(customer, items)).toBe(71);
    });
    it("should return correct premium for a single staff (new customer)", () => {
      const customer = { yearsWithMHPCO: 0 };
      const items = [{ type: "staff", material: "wood", enchantment: 0, cursed: false }];
      expect(quote(customer, items)).toBe(93);
    });
    it("should return correct premium for a single potion (new customer)", () => {
      const customer = { yearsWithMHPCO: 0 };
      const items = [{ type: "potion", material: "liquid", enchantment: 0, cursed: false }];
      expect(quote(customer, items)).toBe(49);
    });
    it("should apply 50% cursed surcharge to the affected item's base premium only", () => {
      const customer = { yearsWithMHPCO: 0 };
      // cursed sword (100G base) + plain amulet (60G base)
      // policy base = 160G; cursed surcharge = 50% of 100G = 50G (not 50% of 160G)
      // first insurance = 10% of 160G = 16G; fee = 5G
      // total = 160 + 50 + 16 + 5 = 231G
      const items = [
        { type: "sword", material: "steel", enchantment: 3, cursed: true },
        { type: "amulet", material: "silver", enchantment: 0, cursed: false },
      ];
      expect(quote(customer, items)).toBe(231);
    });
    it.todo("should apply 30% high-enchantment surcharge when enchantment level >= 5");
    it.todo("should not apply high-enchantment surcharge when enchantment level < 5");
    it.todo("should apply 20% loyalty discount for customers with >= 2 years with MHPCO");
    it.todo("should apply 15% follow-up contract discount for second quote");
    it.todo("should combine premiums for multiple items");
    it.todo("should charge 25G base premium for a single rune component");
    it.todo("should apply block pricing of 60G for exactly 3 alike components");
    it.todo("should not apply block pricing for 2 alike components");
    it.todo("should not apply block pricing for 4 alike components");
    it.todo("should round premium up (in MHPCO's favor)");
  });

  describe("claim", () => {
    it.todo("should reimburse full damage minus 100G deductible for standard item");
    it.todo("should reimburse 50% of damage minus deductible for enchantment >= 8 items");
    it.todo("should reimburse full damage minus deductible for dragon material items");
    it.todo("should apply 50% reimbursement when both dragon material and enchantment >= 8");
    it.todo("should cap payout at remaining policy cap");
    it.todo("should track remaining cap after each claim");
    it.todo("should round payout down (in MHPCO's favor)");
  });
});

