interface Customer { yearsWithMHPCO: number }
interface Item { type: string; cursed?: boolean; enchantment?: number; [key: string]: unknown }

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

export const quote = (customer: Customer, items: Item[], { isFollowUp = false }: { isFollowUp?: boolean } = {}): number => {
  if (items.length === 0) return 5;
  const { policyBase, itemSurcharges } = items.reduce(
    ({ policyBase, itemSurcharges }, item) => {
      const base = BASE_PREMIUMS[item.type];
      return {
        policyBase: policyBase + base,
        itemSurcharges: itemSurcharges + (item.cursed ? base / 2 : 0) + ((item.enchantment ?? 0) >= 5 ? base * 3 / 10 : 0),
      };
    },
    { policyBase: 0, itemSurcharges: 0 }
  );
  const loyaltyDiscount = customer.yearsWithMHPCO >= 2 ? policyBase / 5 : 0;
  const followUpDiscount = isFollowUp ? policyBase * 3 / 20 : 0;
  const firstInsuranceSurcharge = policyBase / 10;
  return policyBase + itemSurcharges + firstInsuranceSurcharge - loyaltyDiscount - followUpDiscount + 5;
};

export const claim = (policy: unknown, incident: unknown): unknown => {
  return undefined;
};

